import{_ as o,c as a,o as d,ag as i}from"./chunks/framework.Bw-5EFTY.js";const m=JSON.parse('{"title":"DAG Media Provider Contract","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-nodes/docs/MEDIA-PROVIDER-CONTRACT.md","filePath":"packages/dag-nodes/docs/MEDIA-PROVIDER-CONTRACT.md"}'),r={name:"packages/dag-nodes/docs/MEDIA-PROVIDER-CONTRACT.md"};function t(c,e,l,n,s,p){return d(),a("div",null,e[0]||(e[0]=[i('<h1 id="dag-media-provider-contract" tabindex="-1">DAG Media Provider Contract <a class="header-anchor" href="#dag-media-provider-contract" aria-label="Permalink to &quot;DAG Media Provider Contract&quot;">​</a></h1><p>This document defines how DAG media nodes consume provider capabilities exposed by <code>@robota-sdk/agent-core</code>.</p><h2 id="capability-contracts" tabindex="-1">Capability Contracts <a class="header-anchor" href="#capability-contracts" aria-label="Permalink to &quot;Capability Contracts&quot;">​</a></h2><ul><li>Image nodes depend on <code>IImageGenerationProvider</code>.</li><li>Video nodes depend on <code>IVideoGenerationProvider</code>.</li><li>Runtime checks must use: <ul><li><code>isImageGenerationProvider(provider)</code></li><li><code>isVideoGenerationProvider(provider)</code></li></ul></li></ul><p>Do not branch behavior by provider name strings.</p><h2 id="image-node-mapping" tabindex="-1">Image Node Mapping <a class="header-anchor" href="#image-node-mapping" aria-label="Permalink to &quot;Image Node Mapping&quot;">​</a></h2><ul><li>Generate node -&gt; <code>generateImage(request)</code></li><li>Edit node -&gt; <code>editImage(request)</code></li><li>Compose node -&gt; <code>composeImage(request)</code></li></ul><p>Expected provider output:</p><ul><li><code>IImageGenerationResult.outputs</code> with <code>IMediaOutputRef[]</code></li><li>No raw binary payload in provider result</li></ul><h2 id="video-node-mapping" tabindex="-1">Video Node Mapping <a class="header-anchor" href="#video-node-mapping" aria-label="Permalink to &quot;Video Node Mapping&quot;">​</a></h2><ul><li>Create run -&gt; <code>createVideo(request)</code></li><li>Poll status -&gt; <code>getVideoJob(jobId)</code></li><li>Cancel run -&gt; <code>cancelVideoJob(jobId)</code></li></ul><p>Expected status union:</p><ul><li><code>queued | running | succeeded | failed | cancelled</code></li></ul><p>Only <code>succeeded</code>, <code>failed</code>, and <code>cancelled</code> are terminal.</p><h2 id="error-contract" tabindex="-1">Error Contract <a class="header-anchor" href="#error-contract" aria-label="Permalink to &quot;Error Contract&quot;">​</a></h2><p>DAG runtime and API server should map provider errors by <code>IProviderMediaError.code</code>:</p><ul><li><code>PROVIDER_AUTH_ERROR</code></li><li><code>PROVIDER_RATE_LIMITED</code></li><li><code>PROVIDER_TIMEOUT</code></li><li><code>PROVIDER_INVALID_REQUEST</code></li><li><code>PROVIDER_UPSTREAM_ERROR</code></li><li><code>PROVIDER_JOB_NOT_FOUND</code></li><li><code>PROVIDER_JOB_NOT_CANCELLABLE</code></li></ul><p>No fallback provider path is allowed when a capability is unsupported.</p>',18)]))}const g=o(r,[["render",t]]);export{m as __pageData,g as default};
